// .npmrc configuration (commit to repo)
package-lock=true
engine-strict=true
save-exact=true

// package.json engines configuration
{
  "engines": {
    "node": ">=20.0.0",
    "npm": ">=10.0.0"
  },
  "scripts": {
    "preinstall": "node check-lockfile.js",
    "install": "npm ci",
    "postinstall": "npm run verify:integrity",
    "verify:integrity": "node verify-integrity.js"
  }
}

// check-lockfile.js - Enforce lockfile usage
const fs = require('fs');
const path = require('path');

const lockfilePath = path.join(__dirname, 'package-lock.json');

if (!fs.existsSync(lockfilePath)) {
  console.error('ERROR: package-lock.json not found!');
  console.error('This is required for reproducible builds.');
  console.error('Run: npm install');
  process.exit(1);
}

// Check if lockfile is up to date
const packageJson = require('./package.json');
const lockfileJson = require('./package-lock.json');

if (packageJson.version !== lockfileJson.version) {
  console.error('ERROR: package-lock.json is out of sync!');
  console.error('Run: npm install --package-lock-only');
  process.exit(1);
}

console.log('package-lock.json verified');

// verify-integrity.js - Check package integrity
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

function verifyPackageIntegrity() {
  const lockfile = require('./package-lock.json');
  const packages = lockfile.packages || {};

  let failures = 0;

  for (const [pkgPath, pkgData] of Object.entries(packages)) {
    if (!pkgData.integrity) continue;

    const fullPath = path.join(__dirname, pkgPath);
    const packageJsonPath = path.join(fullPath, 'package.json');

    if (!fs.existsSync(packageJsonPath)) continue;

    // Verify integrity hash matches
    const expectedIntegrity = pkgData.integrity;
    const algorithm = expectedIntegrity.split('-')[0];

    try {
      const contents = fs.readFileSync(packageJsonPath, 'utf8');
      const hash = crypto.createHash(algorithm.replace('sha', 'sha'));
      hash.update(contents);
      const actualIntegrity = `${algorithm}-${hash.digest('base64')}`;

      if (expectedIntegrity !== actualIntegrity) {
        console.error(`INTEGRITY MISMATCH: ${pkgPath}`);
        failures++;
      }
    } catch (error) {
      console.warn(`Could not verify: ${pkgPath}`);
    }
  }

  if (failures > 0) {
    console.error(`${failures} packages failed integrity check!`);
    console.error('Possible tampering detected. Reinstall dependencies.');
    process.exit(1);
  }

  console.log('All packages passed integrity verification');
}

verifyPackageIntegrity();
